const body = $input.first().json.body || {};
const files = $input.first().json.files || {};

const action = (body.action || '').trim().toLowerCase();
const token  = (body.token  || '').trim();

if (!token)  throw new Error('Missing token');
if (!action) throw new Error('Missing action');
if (!['add','update','delete'].includes(action)) throw new Error('Unknown action: ' + action);

return [{ json: { action, token, body, has_file: !!(files.image || files['image[]']) } }];

const input = $('Route Action').first().json;
const session = $('Validate Session').first().json;
if (!session || !session.tenant_id) throw new Error('Invalid or expired session token');

return [{ json: {
  action:      input.action,
  token:       input.token,
  body:        input.body,
  has_file:    input.has_file,
  tenant_id:   session.tenant_id,
  business_id: session.business_id
}}];

const ctx = $input.first().json;
const body = ctx.body;
const productName = (body.product_name || '').trim();
const mimeType    = (body.mime_type    || 'image/jpeg').trim();

if (!productName) throw new Error('Missing product_name');

const slug = productName.toLowerCase().replace(/[^a-z0-9]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
const ext  = mimeType.split('/')[1] || 'jpg';
const ts   = Date.now();
const objectKey = ctx.tenant_id + '/' + ctx.business_id + '/products/' + slug + '-' + ts + '.' + ext;
const minioUrl  = '[URL]' + objectKey;

return [{ json: {
  tenant_id:    ctx.tenant_id,
  business_id:  ctx.business_id,
  product_name: productName,
  mime_type:    mimeType,
  object_key:   objectKey,
  minio_url:    minioUrl
} }];

const prepareData = $('Prepare Add').first().json;
const webhookItem = $('Actions Webhook').first();

// Binary arrives on the webhook item — find whichever key was used
const binaryData = webhookItem.binary || {};
const imageKey = binaryData.image ? 'image'
  : binaryData['image[]'] ? 'image[]'
  : Object.keys(binaryData)[0] || null;

if (!imageKey) throw new Error('No image binary found in webhook upload');

return [{
  json: {
    tenant_id:    prepareData.tenant_id,
    business_id:  prepareData.business_id,
    product_name: prepareData.product_name,
    mime_type:    prepareData.mime_type,
    object_key:   prepareData.object_key,
    minio_url:    prepareData.minio_url
  },
  binary: {
    data: binaryData[imageKey]
  }
}];

const row = $input.first().json;
return [{ json: {
  id:           row.id,
  product_name: row.product_name,
  display_name: row.display_name || row.product_name,
  minio_url:    row.minio_url,
  price:        row.price || null,
  show_on_store: true,
  image_type:   'product'
}}];

const ctx = $input.first().json;
const body = ctx.body;
const id    = (body.id    || '').trim();
const field = (body.field || '').trim();
const value =  body.value;

if (!id || !field) throw new Error('Missing id or field');
const allowed = ['display_name', 'price', 'show_on_store', 'sort_order'];
if (!allowed.includes(field)) throw new Error('Field not allowed: ' + field);

let castValue;
if (field === 'show_on_store') {
  castValue = (value === 'true' || value === true);
} else if (field === 'price' || field === 'sort_order') {
  castValue = (value === '' || value === null || value === undefined) ? null : parseFloat(value);
} else {
  castValue = String(value || '');
}

return [{ json: { id, field, castValue, tenant_id: ctx.tenant_id, business_id: ctx.business_id } }];

const ctx = $input.first().json;
const id = (ctx.body.id || '').trim();
if (!id) throw new Error('Missing id');
return [{ json: { id, tenant_id: ctx.tenant_id, business_id: ctx.business_id } }];
